(function ($) {
    if (!$) {
        return;
    }

    const defaults = {
        initialCountry: "us",
        separateDialCode: true,
        customPlaceholder: null
    };

    const dialCodes = {
        us: "1",
        ca: "1",
        gb: "44",
        au: "61",
        pk: "92",
        in: "91"
    };

    function normalizeCountry(country) {
        return (country || "us").toLowerCase();
    }

    function digitsOnly(value) {
        return String(value || "").replace(/\D/g, "");
    }

    function initInput(input, options) {
        const $input = $(input);

        if ($input.data("iti-initialized")) {
            return;
        }

        const country = normalizeCountry(options.initialCountry);
        const dialCode = dialCodes[country] || dialCodes.us;
        const placeholder = options.customPlaceholder
            ? options.customPlaceholder("(201) 555-0123")
            : "(201) 555-0123";

        $input.data("iti-country", country);
        $input.data("iti-dial-code", dialCode);
        $input.data("iti-initialized", true);
        $input.attr("placeholder", placeholder);

        if (!$input.parent().hasClass("iti")) {
            $input.wrap('<div class="iti iti--allow-dropdown iti--separate-dial-code"></div>');
            $input.after(
                '<div class="iti__flag-container">' +
                    '<div class="iti__selected-flag" role="button" tabindex="0" aria-label="Selected country: United States">' +
                        '<div class="iti__flag iti__' + country + '"></div>' +
                        '<div class="iti__selected-dial-code">+' + dialCode + '</div>' +
                        '<div class="iti__arrow"></div>' +
                    '</div>' +
                '</div>'
            );
        }
    }

    $.fn.intlTelInput = function (option) {
        if (typeof option === "string") {
            const input = this.get(0);
            const $input = $(input);
            const dialCode = $input.data("iti-dial-code") || dialCodes.us;
            const number = digitsOnly($input.val());

            if (option === "isValidNumber") {
                return number.length >= 10;
            }

            if (option === "getNumber") {
                return number ? "+" + dialCode + number : "";
            }

            return this;
        }

        const options = $.extend({}, defaults, option || {});

        return this.each(function () {
            initInput(this, options);
        });
    };
})(window.jQuery);
